const HOOK_TOKEN = '<CC_HOOK_TOKEN>';
const HMAC_SECRET = '<N8N_WEBHOOK_SECRET>';
const item = $input.first().json;
if (((item.headers||{})['x-marco-hook-token']||'') !== HOOK_TOKEN) return [];
const body = item.body || {};
const text = body.text;
if (!text || typeof text !== 'string') return [];
const data = { source: 'claude-ai', text: text.slice(0, 4000) };
if (['task','milestone','note'].includes(body.kind)) data.kind = body.kind;
if (typeof body.project_slug === 'string' && body.project_slug) data.project_slug = body.project_slug.slice(0, 60);
const payload = JSON.stringify(data);
const c = require('crypto');
const signature = c.createHmac('sha256', HMAC_SECRET).update(payload).digest('hex');
return [{ json: { payload, signature } }];
